for i in range(33,127): D.append(i)
for i in range(161,173): D.append(i)
for i in range(174,256): D.append(i)
for i in range(33): D.append(i)
for i in range(127,161): D.append(i)
D.append(173)
assert len(D)==256
for n,b in enumerate(D):
    cp=b if b in list(range(33,127))+list(range(161,173))+list(range(174,256)) else 256+n-188
    if n<188:
        cp=b
    else:
        cp=68+n
    ch=chr(cp)
    E[ch]=n
    S.append(ch)
with Path('/app/vocab.bpe').open() as fp:
